/**
 * Formata dados da apólice salvos como atributos da tarefa.
 * Suporta apólices de vida (capital, beneficiários) e será extensível
 * para outros ramos conforme a corretora for adicionando.
 */
const task = $input.first().json;
const attrs = task.custom_attributes ?? {};

const temApolice = Boolean(attrs.numero_apolice);

if (!temApolice) {
  return [{
    json: {
      encontrada: false,
      resumo_cliente: 'Não encontrei uma apólice ativa vinculada a essa conversa. Talvez ainda não tenha sido emitida?'
    }
  }];
}

function brl(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }) : '—';
}

const hoje = DateTime.now();
const renovacao = attrs.data_renovacao ? DateTime.fromISO(String(attrs.data_renovacao)) : null;
const diasParaRenovacao = renovacao?.isValid
  ? Math.ceil(renovacao.diff(hoje, 'days').days)
  : null;

const status = diasParaRenovacao !== null && diasParaRenovacao < 0
  ? 'vencida'
  : 'ativa';

const linhas = [
  '📄 *Sua apólice*',
  '',
  `*Número:* ${attrs.numero_apolice}`,
  `*Operadora:* ${attrs.operadora ?? '—'}`,
  `*Plano:* ${attrs.plano_escolhido ?? '—'}`,
  `*Vigência:* ${attrs.data_vigencia ?? '—'} até ${attrs.data_renovacao ?? '—'}`,
  `*Status:* ${status}${diasParaRenovacao !== null ? ` (renova em ${diasParaRenovacao} dias)` : ''}`
];

if (attrs.capital_morte) linhas.push(`*Capital de morte:* ${brl(attrs.capital_morte)}`);
if (attrs.premio_mensal) linhas.push(`*Mensalidade:* ${brl(attrs.premio_mensal)}`);
if (attrs.beneficiarios_resumo) linhas.push(`*Beneficiários:* ${attrs.beneficiarios_resumo}`);

const resumoCliente = linhas.join('\n');

return [{
  json: {
    encontrada: true,
    status,
    ramo: attrs.ramo ?? 'vida',
    numero_apolice: attrs.numero_apolice,
    operadora: attrs.operadora,
    plano_escolhido: attrs.plano_escolhido,
    data_vigencia: attrs.data_vigencia,
    data_renovacao: attrs.data_renovacao,
    dias_para_renovacao: diasParaRenovacao,
    capital_morte: attrs.capital_morte,
    premio_mensal: attrs.premio_mensal,
    beneficiarios_resumo: attrs.beneficiarios_resumo,
    resumo_cliente: resumoCliente,
    task_step: task.board_step?.name ?? null
  }
}];
